(defn extract-bare
  "Extract bare JSON objects from text.
  Returns a vector of parsed JSON values."
  [text]
  (let [pattern #"(?s)\{[^{}]*\}"]
    (->> (re-seq pattern text)
         (keep #(try (json/parse-string % true) (catch Exception _ nil)))
         vec)))


